using System.Collections.Generic;
using CustomInspector;
using Mirror;
using UI;
using UnityEngine;
using static Prometeo.CarController;

namespace PlayerBehaviour
{
    public class PlayerDriveController : DriveController
    {
        public PlayerDriveController() : base(Activation.LocalAndServer) { }


        protected override void Update()
        {
            base.Update();

            if (Input.GetKeyDown(KeyCode.LeftShift))
            {
                SendNitro();
            }
        }


        Acceleration prevAcceleration = Acceleration.Neutral;
        Steering prevSteering = Steering.Straight;
        bool prevBrake = false;

        [ClientCallback]
        public void FixedUpdate()
        {
            if (!isLocalPlayer) return;


            var currentAcceleration = Acceleration.Neutral;
            if (Input.GetKey(KeyCode.W) && !Input.GetKey(KeyCode.S))
                currentAcceleration = Acceleration.Positive;
            if (Input.GetKey(KeyCode.S) && !Input.GetKey(KeyCode.W))
                currentAcceleration = Acceleration.Negative;


            var currentSteering = Steering.Straight;
            if (Input.GetKey(KeyCode.D) && !Input.GetKey(KeyCode.A))
                currentSteering = Steering.Right;
            if (Input.GetKey(KeyCode.A) && !Input.GetKey(KeyCode.D))
                currentSteering = Steering.Left;

            var currentBrake = Input.GetKey(KeyCode.Space);

            if (currentAcceleration != prevAcceleration
                || currentSteering != prevSteering
                || currentBrake != prevBrake)
            {
                prevAcceleration = currentAcceleration;
                prevSteering = currentSteering;
                prevBrake = currentBrake;
                SendNewInput(motor: currentAcceleration, steering: currentSteering, handbrake: currentBrake);
            }
        }
    }

    [System.Serializable]
    public class AxleInfo
    {
        public WheelCollider leftWheel;
        public WheelCollider rightWheel;
        public bool motor;
        public bool steering;
    }
}


Brauchst du noch weiteren code? (für das car movement)

Um das neue Input System von Unity zu verwenden, müssen Sie einige Schritte durchführen, um Ihren bestehenden Code umzuschreiben. Ihrer Beschreibung nach zu urteilen, scheint Ihr Spiel ein Rennspiel zu sein, in dem Tastendrücke verwendet werden, um ein Auto zu steuern.

Hier die Schritte, um den gezeigten Code auf das neue Input-System umzustellen:

1. **Aktivieren Sie das neue Input-System** wie in meinem vorherigen Beitrag beschrieben.

2. **Erstellen Sie ein Input Actions Asset**, um Ihre Steueraktionen zu definieren. Dies tun Sie im Unity Editor:

    - Rechtsklick im Projektfenster und wählen Sie `Create > Input Actions`.
    - Öffnen Sie die neu erstellte Input Actions Datei.
    - Definieren Sie Aktionen für "Acceleration", "Steering" und "Nitro", und binden Sie sie an entsprechende Tasten (W, A, S, D, Left Shift, Space).

3. **Referenzieren Sie das Input Actions Asset in Ihrem Skript**. Erstellen Sie dazu ein Feld im `PlayerDriveController`-Klasse, um das erstellte Input Actions Asset zu referenzieren.

4. **Initialisieren Sie die Input Actions im Code**. Hierzu müssen Sie das Input Actions Asset laden, aktivieren und die entsprechenden Callbacks einrichten.

Hier ist ein Beispiel, wie Ihr umgeschriebener `PlayerDriveController` aussehen könnte (bitte beachten Sie, dass die Namen Ihrer Input Actions denen im erstellten Input Actions Asset entsprechen müssen):

```csharp
using UnityEngine;
using UnityEngine.InputSystem; // Neuer Namespace für das neue Input-System

namespace PlayerBehaviour
{
    public class PlayerDriveController : DriveController
    {
        [SerializeField]
        private InputActionAsset inputActionAsset; // Referenz auf das Input Action Asset

        // Referenzen auf spezifische Input Actions
        private InputAction nitroAction;
        private InputAction accelerationAction;
        private InputAction steeringAction;
        private InputAction brakeAction;

        public PlayerDriveController() : base(Activation.LocalAndServer) { }

        private void OnEnable()
        {
            // Lade die Aktionen und aktiviere sie
            nitroAction = inputActionAsset.FindAction("Nitro");
            accelerationAction = inputActionAsset.FindAction("Acceleration");
            steeringAction = inputActionAsset.FindAction("Steering");
            brakeAction = inputActionAsset.FindAction("Brake");

            nitroAction.performed += ctx => SendNitro(); // Binden des Events an den Callback
            nitroAction.Enable();

            accelerationAction.Enable();
            steeringAction.Enable();
            brakeAction.Enable();
        }

        private void OnDisable()
        {
            // Deaktiviere die Aktionen, wenn das Objekt deaktiviert wird
            nitroAction.Disable();
            accelerationAction.Disable();
            steeringAction.Disable();
            brakeAction.Disable();
        }

        [ClientCallback]
        public void FixedUpdate()
        {
            if (!isLocalPlayer) return;

            var currentAcceleration = accelerationAction.ReadValue<float>(); // Diese Methode gibt einen Wert zwischen -1 und 1 zurück
            var currentSteering = steeringAction.ReadValue<float>(); // Diese Methode gibt einen Wert zwischen -1 und 1 zurück
            var currentBrake = brakeAction.triggered; // Dies gibt true zurück, wenn die Bremse (Space) gedrückt wird

            // Führen Sie hier Ihre Logik zur Umwandlung von Float-Werten in Ihre Acceleration- und Steering-Enumerationen durch

            /* Code zum Senden von Steuersignalen */
        }
    }
}
```

5. **Implementieren Sie Ihre Logik**, um `currentAcceleration` und `currentSteering` in die entsprechenden Enumerationswerte zu konvertieren. Wenn Ihr Spiel eine analoge Steuerung unterstützt, können Sie die Float-Werte direkt verwenden, um eine proportionale Steuerung zu ermöglichen. Falls Sie eine digitale (Ein/Aus) Steuerung haben, möchten Sie vielleicht eine Konversion basierend auf einem Schwellwert durchführen.

6. **Testen Sie Ihr Spiel**, um sicherzustellen, dass alle Änderungen korrekt funktionieren.

Bitte beachten Sie, dass dieser code nur ein Beispiel ist und entsprechend den genauen Namen der definierten Input Actions angepasst werden muss. Ebenfalls muss die Logik zur Umwandlung von Float-Werten in Ihre spezifischen Enumerationswerte implementiert werden.

using UnityEngine;
using UnityEngine.UI;
using Mirror;
using System;
using CustomInspector;
using System.Linq;

namespace Prometeo
{
    /// <summary>
    /// The base of the skript is downloaded from UnityAsset-Store: Prometeo: https://assetstore.unity.com/packages/tools/physics/prometeo-car-controller-209444
    /// BUT EDITED!!!, so NOT 1 to 1 same
    /// </summary>
    public class CarController : MonoBehaviour
    {
        //CAR
        [Title("CAR")]

        [Space(10)]
        [Range(5, 80), Unit("meter/sec")]
        public float maxSpeed = 100f;
        public float MaxSpeed_kmh => maxSpeed * 3.6f;

        [Range(2, 50), Unit("meter/sec")]
        public int maxReverseSpeed = 50;
        [Range(1, 10)]
        public int accelerationMultiplier = 3;
        [Space(10)]
        [Range(10, 45)]
        public int maxSteeringAngle = 30;
        [Range(0.1f, 1f)]
        public float steeringSpeed = 0.5f;
        [Space(10)]
        [Range(100, 600)]
        public int brakeForce = 350;
        [Range(1, 10)]
        public int decelerationMultiplier = 2;
        [Range(1, 10)]
        public int handbrakeDriftMultiplier = 5;
        [Space(10)]
        public Vector3 bodyMassCenter;

        [SerializeField, ReadOnly]
        MyNetworkRigidbody carRigidbody;

        //WHEELS
        [Title("WHEELS")]

        [ForceFill] public WheelCollider frontLeftCollider;
        [ForceFill] public WheelCollider frontRightCollider;
        [ForceFill] public WheelCollider rearLeftCollider;
        [ForceFill] public WheelCollider rearRightCollider;

        [Space(10)]
        [SerializeField] bool animateWheelMeshes = false;
        [ShowIf(nameof(animateWheelMeshes)), ForceFill] public GameObject frontLeftMesh;
        [ShowIf(nameof(animateWheelMeshes)), ForceFill] public GameObject frontRightMesh;
        [ShowIf(nameof(animateWheelMeshes)), ForceFill] public GameObject rearLeftMesh;
        [ShowIf(nameof(animateWheelMeshes)), ForceFill] public GameObject rearRightMesh;

        //EFFECTS
        [Title("EFFECTS")]
        [ShowIf(StaticConditions.IsNotPlaying, style = DisabledStyle.GreyedOut, indent = 0)]
        public bool useEffects = true;
        [ShowIf(nameof(useEffects)), SerializeField, AssetsOnly] GameObject tireSkidPrefab;
        [ShowIf(nameof(useEffects)), SerializeField, AssetsOnly] GameObject tireSmokePrefab;

        //UI SPEED
        [Title("UI")]

        public bool useUI = false;
        [ShowIf(nameof(useUI))] public Text carSpeedText;

        //SOUNDS
        [Title("SOUNDS")]

        public bool useSounds = false;
        [ShowIf(nameof(useSounds))] public AudioSource carEngineSound;
        [ShowIf(nameof(useSounds))] public AudioSource tireScreechSound;
        [ShowIf(nameof(useSounds))] float initialCarEngineSoundPitch;

        //CAR DATA
        [Header("CAR DATA", order = -5)]

        [ReadOnly(order = -11), ShowIf(StaticConditions.IsPlaying, order = -10)]
        public float carSpeed;
        [ReadOnly, ShowIf(StaticConditions.IsPlaying)]
        public bool isDrifting;
        [ReadOnly, ShowIf(StaticConditions.IsPlaying)]
        public bool isTractionLocked;

        //control mode
        [Title("CONTROL MODE")]

        [SerializeField, Tooltip("If set to false, the script does not read input self. Inputs have to be called from outside of the script with:\n" +
        "CurrentAcceleration, CurrentSteering, CurrentHandbrake")]
        bool readInputSelf = true;

        //PRIVATE VARIABLES

        float steeringAxis;
        float throttleAxis;
        float driftingAxis;
        Vector3 localVelocity;
        bool deceleratingCar;

        WheelFrictionCurve FLwheelFriction;
        float FLWextremumSlip;
        WheelFrictionCurve FRwheelFriction;
        float FRWextremumSlip;
        WheelFrictionCurve RLwheelFriction;
        float RLWextremumSlip;
        WheelFrictionCurve RRwheelFriction;
        float RRWextremumSlip;

        TrailRenderer rlwTireSkid;
        TrailRenderer rrwTireSkid;
        ParticleSystem rlwTireSmoke;
        ParticleSystem rrwTireSmoke;

        //INPUT
        public enum Steering { Right, Straight, Left }
        public enum Acceleration { Positive, Neutral, Negative }
        public Steering CurrentSteering
        {
            get => currentSteering;
            set { if (!readInputSelf) currentSteering = value; else throw new ArgumentException("Could not set input. Input is self-read by class."); }
        }
        Steering currentSteering = Steering.Straight;
        public Acceleration CurrentAcceleration
        {
            get => currentAcceleration;
            set { if (!readInputSelf) currentAcceleration = value; else throw new ArgumentException("Could not set input. Input is self-read by class."); }
        }
        Acceleration currentAcceleration = Acceleration.Neutral;
        public bool CurrentHandbrake
        {
            get => currentHandbrake;
            set
            {
                if (!readInputSelf)
                {
                    currentHandbrake = value;
                    if (!value)
                        RecoverTraction();
                }
                else throw new ArgumentException("Could not set input. Input is self-read by class.");
            }
        }
        bool currentHandbrake = false;

        //START

        public void Initialize(MyNetworkRigidbody rb)
        {
            if (rb == null)
                throw new ArgumentException("NullReference passed!");
            this.carRigidbody = rb;

            carRigidbody.CenterOfMass = bodyMassCenter;
        }
        private void Start()
        {
            //effects
            if (useEffects)
            {
                rlwTireSkid =  Instantiate(original: tireSkidPrefab,  position: rearLeftCollider.transform.position + Vector3.down *  rearLeftCollider.radius , rotation: rearLeftCollider.transform.rotation  * tireSkidPrefab.transform.localRotation,  parent: rearLeftCollider.transform ).GetComponentOrFail<TrailRenderer>();
                rrwTireSkid =  Instantiate(original: tireSkidPrefab,  position: rearRightCollider.transform.position + Vector3.down * rearRightCollider.radius, rotation: rearRightCollider.transform.rotation * tireSkidPrefab.transform.localRotation,  parent: rearRightCollider.transform).GetComponentOrFail<TrailRenderer>();
                rlwTireSmoke = Instantiate(original: tireSmokePrefab, position: rearLeftCollider.transform.position + Vector3.down *  rearLeftCollider.radius , rotation: rearLeftCollider.transform.rotation  * tireSmokePrefab.transform.localRotation, parent: rearLeftCollider.transform ).GetComponentOrFail<ParticleSystem>();
                rrwTireSmoke = Instantiate(original: tireSmokePrefab, position: rearRightCollider.transform.position + Vector3.down * rearRightCollider.radius, rotation: rearRightCollider.transform.rotation * tireSmokePrefab.transform.localRotation, parent: rearRightCollider.transform).GetComponentOrFail<ParticleSystem>();
            }


            //wheel physics
            FLwheelFriction = new WheelFrictionCurve();
            FLwheelFriction.extremumSlip = frontLeftCollider.sidewaysFriction.extremumSlip;
            FLWextremumSlip = frontLeftCollider.sidewaysFriction.extremumSlip;
            FLwheelFriction.extremumValue = frontLeftCollider.sidewaysFriction.extremumValue;
            FLwheelFriction.asymptoteSlip = frontLeftCollider.sidewaysFriction.asymptoteSlip;
            FLwheelFriction.asymptoteValue = frontLeftCollider.sidewaysFriction.asymptoteValue;
            FLwheelFriction.stiffness = frontLeftCollider.sidewaysFriction.stiffness;
            FRwheelFriction = new WheelFrictionCurve();
            FRwheelFriction.extremumSlip = frontRightCollider.sidewaysFriction.extremumSlip;
            FRWextremumSlip = frontRightCollider.sidewaysFriction.extremumSlip;
            FRwheelFriction.extremumValue = frontRightCollider.sidewaysFriction.extremumValue;
            FRwheelFriction.asymptoteSlip = frontRightCollider.sidewaysFriction.asymptoteSlip;
            FRwheelFriction.asymptoteValue = frontRightCollider.sidewaysFriction.asymptoteValue;
            FRwheelFriction.stiffness = frontRightCollider.sidewaysFriction.stiffness;
            RLwheelFriction = new WheelFrictionCurve();
            RLwheelFriction.extremumSlip = rearLeftCollider.sidewaysFriction.extremumSlip;
            RLWextremumSlip = rearLeftCollider.sidewaysFriction.extremumSlip;
            RLwheelFriction.extremumValue = rearLeftCollider.sidewaysFriction.extremumValue;
            RLwheelFriction.asymptoteSlip = rearLeftCollider.sidewaysFriction.asymptoteSlip;
            RLwheelFriction.asymptoteValue = rearLeftCollider.sidewaysFriction.asymptoteValue;
            RLwheelFriction.stiffness = rearLeftCollider.sidewaysFriction.stiffness;
            RRwheelFriction = new WheelFrictionCurve();
            RRwheelFriction.extremumSlip = rearRightCollider.sidewaysFriction.extremumSlip;
            RRWextremumSlip = rearRightCollider.sidewaysFriction.extremumSlip;
            RRwheelFriction.extremumValue = rearRightCollider.sidewaysFriction.extremumValue;
            RRwheelFriction.asymptoteSlip = rearRightCollider.sidewaysFriction.asymptoteSlip;
            RRwheelFriction.asymptoteValue = rearRightCollider.sidewaysFriction.asymptoteValue;
            RRwheelFriction.stiffness = rearRightCollider.sidewaysFriction.stiffness;

            if (carEngineSound != null)
            {
                initialCarEngineSoundPitch = carEngineSound.pitch;
            }

            if (useUI)
            {
                InvokeRepeating(nameof(CarSpeedUI), 0f, 0.1f);
            }
            else if (!useUI)
            {
                if (carSpeedText != null)
                {
                    carSpeedText.text = "0";
                }
            }

            if (useSounds)
            {
                InvokeRepeating(nameof(CarSounds), 0f, 0.1f);
            }
            else if (!useSounds)
            {
                if (carEngineSound != null)
                {
                    carEngineSound.Stop();
                }
                if (tireScreechSound != null)
                {
                    tireScreechSound.Stop();
                }
            }
        }

        //UPDATE

        private void Update()
        {
            if (carRigidbody == null) //not initailized yet
                return;

            //CAR DATA
            localVelocity = transform.InverseTransformDirection(carRigidbody.Velocity);
            carSpeed = localVelocity.magnitude;

            //INPUT
            if (readInputSelf)
            {
                //states
                currentAcceleration = Acceleration.Neutral;
                if (Input.GetKey(KeyCode.W) && !Input.GetKey(KeyCode.S))
                    currentAcceleration = Acceleration.Positive;
                if (Input.GetKey(KeyCode.S) && !Input.GetKey(KeyCode.W))
                    currentAcceleration = Acceleration.Negative;

                currentSteering = Steering.Straight;
                if (Input.GetKey(KeyCode.D) && !Input.GetKey(KeyCode.A))
                    currentSteering = Steering.Right;
                if (Input.GetKey(KeyCode.A) && !Input.GetKey(KeyCode.D))
                    currentSteering = Steering.Left;

                currentHandbrake = Input.GetKey(KeyCode.Space);

                //trigger
                if (Input.GetKeyUp(KeyCode.Space))
                    RecoverTraction();
            }

            //CAR PHYSICS

            if (currentAcceleration == Acceleration.Positive && !currentHandbrake)
            {
                CancelInvoke(nameof(DecelerateCar));
                deceleratingCar = false;
                GoForward();
            }
            else if (currentAcceleration == Acceleration.Negative && !currentHandbrake)
            {
                CancelInvoke(nameof(DecelerateCar));
                deceleratingCar = false;
                GoReverse();
            }
            else // currentAcceleration == Acceleration.Neutral
            {
                ThrottleOff();

                if (currentHandbrake)
                {
                    CancelInvoke(nameof(DecelerateCar));
                    deceleratingCar = false;
                    Handbrake();
                }
                else if(!deceleratingCar)
                {
                    InvokeRepeating(nameof(DecelerateCar), 0f, 0.1f);
                    deceleratingCar = true;
                }
            }

            if (currentSteering == Steering.Left)
            {
                TurnLeft();
            }
            else if (currentSteering == Steering.Right)
            {
                TurnRight();
            }
            else // currentSteering == Steering.Straight
            {
                if (steeringAxis != 0f)
                    ResetSteeringAngle();
            }

            if(animateWheelMeshes)
                AnimateWheelMeshes();
        }


        //UI CAR SPEED
        public void CarSpeedUI()
        {
            if (useUI)
            {
                try
                {
                    float absoluteCarSpeed = Mathf.Abs(carSpeed);
                    carSpeedText.text = Mathf.RoundToInt(absoluteCarSpeed).ToString();
                }
                catch (Exception ex)
                {
                    Debug.LogWarning(ex);
                }
            }
        }

        //CAR SOUNDS
        public void CarSounds()
        {
            if (useSounds)
            {
                try
                {
                    if (carEngineSound != null)
                    {
                        float engineSoundPitch = initialCarEngineSoundPitch + (Mathf.Abs(carSpeed) / 25f);
                        carEngineSound.pitch = engineSoundPitch;
                    }
                    if ((isDrifting) || (isTractionLocked && Mathf.Abs(carSpeed) > 12f))
                    {
                        if (!tireScreechSound.isPlaying)
                        {
                            tireScreechSound.Play();
                        }
                    }
                    else if ((!isDrifting) && (!isTractionLocked || Mathf.Abs(carSpeed) < 12f))
                    {
                        tireScreechSound.Stop();
                    }
                }
                catch (Exception ex)
                {
                    Debug.LogWarning(ex);
                }
            }
            else if (!useSounds)
            {
                if (carEngineSound != null && carEngineSound.isPlaying)
                {
                    carEngineSound.Stop();
                }
                if (tireScreechSound != null && tireScreechSound.isPlaying)
                {
                    tireScreechSound.Stop();
                }
            }

        }

        //STEERING METHODS
        public void TurnLeft()
        {
            steeringAxis = steeringAxis - (Time.deltaTime * 10f * steeringSpeed);
            if (steeringAxis < -1f)
            {
                steeringAxis = -1f;
            }
            var steeringAngle = steeringAxis * maxSteeringAngle;
            frontLeftCollider.steerAngle = Mathf.Lerp(frontLeftCollider.steerAngle, steeringAngle, steeringSpeed);
            frontRightCollider.steerAngle = Mathf.Lerp(frontRightCollider.steerAngle, steeringAngle, steeringSpeed);
        }

        public void TurnRight()
        {
            steeringAxis = steeringAxis + (Time.deltaTime * 10f * steeringSpeed);
            if (steeringAxis > 1f)
            {
                steeringAxis = 1f;
            }
            var steeringAngle = steeringAxis * maxSteeringAngle;
            frontLeftCollider.steerAngle = Mathf.Lerp(frontLeftCollider.steerAngle, steeringAngle, steeringSpeed);
            frontRightCollider.steerAngle = Mathf.Lerp(frontRightCollider.steerAngle, steeringAngle, steeringSpeed);
        }

        public void ResetSteeringAngle()
        {
            if (steeringAxis < 0f)
            {
                steeringAxis = steeringAxis + (Time.deltaTime * 10f * steeringSpeed);
            }
            else if (steeringAxis > 0f)
            {
                steeringAxis = steeringAxis - (Time.deltaTime * 10f * steeringSpeed);
            }
            if (Mathf.Abs(frontLeftCollider.steerAngle) < 1f)
            {
                steeringAxis = 0f;
            }
            var steeringAngle = steeringAxis * maxSteeringAngle;
            frontLeftCollider.steerAngle = Mathf.Lerp(frontLeftCollider.steerAngle, steeringAngle, steeringSpeed);
            frontRightCollider.steerAngle = Mathf.Lerp(frontRightCollider.steerAngle, steeringAngle, steeringSpeed);
        }

        void AnimateWheelMeshes()
        {
            try
            {
                Quaternion FLWRotation;
                Vector3 FLWPosition;
                frontLeftCollider.GetWorldPose(out FLWPosition, out FLWRotation);
                frontLeftMesh.transform.position = FLWPosition;
                frontLeftMesh.transform.rotation = FLWRotation;

                Quaternion FRWRotation;
                Vector3 FRWPosition;
                frontRightCollider.GetWorldPose(out FRWPosition, out FRWRotation);
                frontRightMesh.transform.position = FRWPosition;
                frontRightMesh.transform.rotation = FRWRotation;

                Quaternion RLWRotation;
                Vector3 RLWPosition;
                rearLeftCollider.GetWorldPose(out RLWPosition, out RLWRotation);
                rearLeftMesh.transform.position = RLWPosition;
                rearLeftMesh.transform.rotation = RLWRotation;

                Quaternion RRWRotation;
                Vector3 RRWPosition;
                rearRightCollider.GetWorldPose(out RRWPosition, out RRWRotation);
                rearRightMesh.transform.position = RRWPosition;
                rearRightMesh.transform.rotation = RRWRotation;
            }
            catch (Exception ex)
            {
                Debug.LogWarning(ex);
            }
        }

        //ENGINE AND BREAKING METHODS
        public void GoForward()
        {
            if (Mathf.Abs(localVelocity.x) > 2.5f)
            {
                isDrifting = true;
                DriftCarPS();
            }
            else
            {
                isDrifting = false;
                DriftCarPS();
            }
            throttleAxis = throttleAxis + (Time.deltaTime * 3f);
            if (throttleAxis > 1f)
            {
                throttleAxis = 1f;
            }
            if (localVelocity.z < -1f)
            {
                Brakes();
            }
            else
            {
                if (carSpeed < maxSpeed)
                {
                    frontLeftCollider.brakeTorque = 0;
                    frontLeftCollider.motorTorque = (accelerationMultiplier * 50f) * throttleAxis;
                    frontRightCollider.brakeTorque = 0;
                    frontRightCollider.motorTorque = (accelerationMultiplier * 50f) * throttleAxis;
                    rearLeftCollider.brakeTorque = 0;
                    rearLeftCollider.motorTorque = (accelerationMultiplier * 50f) * throttleAxis;
                    rearRightCollider.brakeTorque = 0;
                    rearRightCollider.motorTorque = (accelerationMultiplier * 50f) * throttleAxis;
                }
                else
                {
                    frontLeftCollider.motorTorque = 0;
                    frontRightCollider.motorTorque = 0;
                    rearLeftCollider.motorTorque = 0;
                    rearRightCollider.motorTorque = 0;
                }
            }
        }
        public void GoReverse()
        {
            if (Mathf.Abs(localVelocity.x) > 2.5f)
            {
                isDrifting = true;
                DriftCarPS();
            }
            else
            {
                isDrifting = false;
                DriftCarPS();
            }
            throttleAxis = throttleAxis - (Time.deltaTime * 3f);
            if (throttleAxis < -1f)
            {
                throttleAxis = -1f;
            }
            if (localVelocity.z > 1f)
            {
                Brakes();
            }
            else
            {
                if (Mathf.Abs(Mathf.RoundToInt(carSpeed)) < maxReverseSpeed)
                {
                    frontLeftCollider.brakeTorque = 0;
                    frontLeftCollider.motorTorque = (accelerationMultiplier * 50f) * throttleAxis;
                    frontRightCollider.brakeTorque = 0;
                    frontRightCollider.motorTorque = (accelerationMultiplier * 50f) * throttleAxis;
                    rearLeftCollider.brakeTorque = 0;
                    rearLeftCollider.motorTorque = (accelerationMultiplier * 50f) * throttleAxis;
                    rearRightCollider.brakeTorque = 0;
                    rearRightCollider.motorTorque = (accelerationMultiplier * 50f) * throttleAxis;
                }
                else
                {
                    frontLeftCollider.motorTorque = 0;
                    frontRightCollider.motorTorque = 0;
                    rearLeftCollider.motorTorque = 0;
                    rearRightCollider.motorTorque = 0;
                }
            }
        }

        public void ThrottleOff()
        {
            frontLeftCollider.motorTorque = 0;
            frontRightCollider.motorTorque = 0;
            rearLeftCollider.motorTorque = 0;
            rearRightCollider.motorTorque = 0;
        }

        public void DecelerateCar()
        {
            if (Mathf.Abs(localVelocity.x) > 2.5f)
            {
                isDrifting = true;
                DriftCarPS();
            }
            else
            {
                isDrifting = false;
                DriftCarPS();
            }
            if (throttleAxis != 0f)
            {
                if (throttleAxis > 0f)
                {
                    throttleAxis = throttleAxis - (Time.deltaTime * 10f);
                }
