using UnityEngine.InputSystem;

namespace PlayerBehaviour
{
    public class PlayerShooting : Shooting
    {
        private PlayerControls playerControls;

        public PlayerShooting() : base(Activation.Local) { }

        protected override void Awake()
        {
            base.Awake();

            playerControls = new PlayerControls();

            // Subscribe to the actions in Awake, if the GameObject is not going to be disabled/enabled often
            playerControls.Player.Shoot.performed += OnShootPerformed;
            playerControls.Player.Shoot.canceled += OnShootCanceled;
        }

        private void OnEnable()
        {
            playerControls.Enable(); // Make sure to enable the input when the object is active
        }

        private void OnDisable()
